mapper.select:
SELECT scene.name sceneName, area.name areaName, ap.name apName, ps.time, IFNULL((ps.packetLossRate),0) packetLossRate FROM scene LEFT JOIN pingspeed ps ON ps.`sceneId`=scene.`id` LEFT JOIN area ON ps.`areaId`=area.`id` LEFT JOIN ap ON ps.`apId`=ap.`id` where 1=1
and scene.id=#{sceneId}
order by scene.id

SELECT scene.name sceneName, area.name areaName, ap.name apName, ps.time, IFNULL((ps.packetLossRate),0) packetLossRate FROM area LEFT JOIN pingspeed ps ON ps.`areaId`=area.`id` LEFT JOIN scene ON ps.`sceneId`=scene.`id` LEFT JOIN ap ON ps.`apId`=ap.`id` where 1=1
and area.sceneId=#{sceneId}
order by scene.id

SELECT scene.name sceneName, area.name areaName, ap.name apName, ps.time, IFNULL((ps.packetLossRate),0) packetLossRate FROM ap LEFT JOIN pingspeed ps ON ps.`apId`=ap.`id` LEFT JOIN scene ON ps.`sceneId`=scene.`id` LEFT JOIN area ON ps.`areaId`=area.`id` where 1=1
and ap.areaId=#{areaId}
order by scene.id

SELECT ap.id,ap.name apName,scene.name sceneName, area.name areaName FROM pingspeed ps LEFT JOIN scene ON scene.id=ps.sceneId LEFT JOIN area ON ps.areaId=area.id LEFT JOIN ap ON ps.apId=ap.id WHERE 1=1
and scene.name IS NOT NULL
and scene.name IS NOT NULL and scene.id=#{sceneId}
and area.name IS NOT NULL and area.id=#{areaId}

select ps.`id`, ps.`address`, ps.`macAddress`, ps.`macAddress5G`, ps.`time`, ps.`size`, ps.`sendQuantity`, ps.`receiveQuantity`, ps.`packetLossRate`, ps.`avgRTT`, ps.`minRTT`, ps.`maxRTT`, ps.`meanDifference`, ps.`sceneId`, ps.`areaId`, ps.`apId`, ps.`speedometer`, scene.`name` sceneName, area.`name` areaName, ap.`name` apName FROM pingspeed ps LEFT JOIN scene ON ps.sceneId=scene.id LEFT JOIN area ON ps.areaId =area.id LEFT JOIN ap ON ps.apId=ap.id WHERE 1=1 and ps.packetLossRate >= ${lostPacketRatePassValue}
AND scene.name=#{sceneName}
AND area.name=#{areaName}
AND ap.name=#{apName}

select ps.`id`, ps.`address`, ps.`macAddress`, ps.`macAddress5G`, ps.`time`, ps.`size`, ps.`sendQuantity`, ps.`receiveQuantity`, ps.`packetLossRate`, ps.`avgRTT`, ps.`minRTT`, ps.`maxRTT`, ps.`meanDifference`, ps.`sceneId`, ps.`areaId`, ps.`apId`, ps.`speedometer`, scene.`name` sceneName, area.`name` areaName, ap.`name` apName FROM pingspeed ps LEFT JOIN scene ON ps.sceneId=scene.id LEFT JOIN area ON ps.areaId =area.id LEFT JOIN ap ON ps.apId=ap.id WHERE 1=1 and ps.packetLossRate < ${lostPacketRatePassValue}
AND scene.name=#{sceneName}
AND area.name=#{areaName}
AND ap.name=#{apName}

select ps.`id`, ps.`address`, ps.`macAddress`, ps.`macAddress5G`, ps.`time`, ps.`size`, ps.`sendQuantity`, ps.`receiveQuantity`, ps.`packetLossRate`, ps.`avgRTT`, ps.`minRTT`, ps.`maxRTT`, ps.`meanDifference`, ps.`sceneId`, ps.`areaId`, ps.`apId`, ps.`speedometer`, scene.`name` sceneName, area.`name` areaName, ap.`name` apName FROM pingspeed ps LEFT JOIN scene ON ps.sceneId=scene.id LEFT JOIN area ON ps.areaId =area.id LEFT JOIN ap ON ps.apId=ap.id WHERE 1=1
AND scene.name=#{sceneName}
AND area.name=#{areaName}
AND ap.name=#{apName}
